      </div>

      <!-- 单价对比 -->
      <div class="chart-section animate__animated animate__fadeInUp">
        <div class="section-header">
          <h3 class="section-title">每平米租金对比</h3>
          <p class="section-desc">单价差异更直观地反映区域价值</p>
        </div>
        <div class="chart-container">
          <v-chart :option="pricePerSqmOption" autoresize />
        </div>
        <div class="insight-box">
          <i class="el-icon-info"></i>
          <span>体育西路单价95元/㎡，是龙归（40元/㎡）的2.4倍</span>
        </div>
      </div>

      <!-- 租金分布箱线图 -->
      <div class="chart-section animate__animated animate__fadeIn">
        <div class="section-header">
          <h3 class="section-title">租金分布与波动</h3>
          <p class="section-desc">不止于平均值：中位数、极值与差异指数</p>
        </div>
        <div class="stats-grid">
          <div class="stat-card" v-for="(station, key) in rentStats" :key="key">
            <div class="stat-station">{{ station.station }}</div>
            <div class="stat-row">
              <span class="stat-label">平均值</span>
              <span class="stat-value primary">{{ station.avgRent }}元</span>
            </div>
            <div class="stat-row">
              <span class="stat-label">中位数</span>
              <span class="stat-value">{{ station.medianRent }}元</span>
            </div>
            <div class="stat-row">
              <span class="stat-label">价格区间</span>
              <span class="stat-value">{{ station.minRent }}-{{ station.maxRent }}元</span>
            </div>
            <div class="stat-row">
              <span class="stat-label">差异指数</span>
              <span class="stat-value" :class="getVariationClass(station.variationIndex)">
