<script>
import VChart from 'vue-echarts';
import { use } from 'echarts/core';
import { CanvasRenderer } from 'echarts/renderers';
import { BarChart, PieChart, ScatterChart } from 'echarts/charts';
import {
  TitleComponent,
  TooltipComponent,
  LegendComponent,
  GridComponent
} from 'echarts/components';
import { rentData, quadrantData } from '@/data/realData';

use([
  CanvasRenderer,
  BarChart,
  PieChart,
  ScatterChart,
  TitleComponent,
  TooltipComponent,
  LegendComponent,
  GridComponent
]);

export default {
  name: 'DataVisualizationPage',
  components: {
    VChart
  },
  data() {
    return {
      rentStats: rentData
    }
  },
  computed: {
    // 租金对比柱状图
    rentComparisonOption() {
      const stations = Object.values(rentData).map(d => d.station);
      const rents = Object.values(rentData).map(d => d.avgRent);
      
      return {
        tooltip: {
          trigger: 'axis',
          axisPointer: { type: 'shadow' },
          formatter: '{b}<br/>平均租金: {c}元/月'
        },
        grid: {
          left: '3%',
          right: '4%',
          bottom: '3%',
          containLabel: true
        },
        xAxis: {
          type: 'category',
          data: stations,
          axisLabel: {
            interval: 0,
            rotate: 30,
            fontSize: 12
          }
        },
        yAxis: {
          type: 'value',
          name: '租金(元/月)',
          axisLabel: {
            formatter: '{value}'
          }
        },
        series: [{
          type: 'bar',
          data: rents,
          itemStyle: {
            color: (params) => {
              const colors = ['#F56C6C', '#E6A23C', '#67C23A', '#E6A23C', '#67C23A'];
              return colors[params.dataIndex] || '#409EFF';
            }
          },
          label: {
            show: true,
            position: 'top',
            formatter: '{c}元',
            fontSize: 11
          },
          barWidth: '50%'
        }]
      };
    },
    
    // 单价对比
    pricePerSqmOption() {
      const stations = Object.values(rentData).map(d => d.station);
      const prices = Object.values(rentData).map(d => d.pricePerSqm);
      
      return {
        tooltip: {
          trigger: 'axis',
          formatter: '{b}<br/>单价: {c}元/㎡'
        },
        grid: {
          left: '3%',
          right: '4%',
          bottom: '3%',
          containLabel: true
        },
        xAxis: {
          type: 'category',
          data: stations,
          axisLabel: {
            interval: 0,
            rotate: 30,
            fontSize: 12
          }
        },
        yAxis: {
          type: 'value',
          name: '单价(元/㎡)',
          axisLabel: {
            formatter: '{value}'
          }
        },
        series: [{
          type: 'bar',
          data: prices,
          itemStyle: {
            color: {
              type: 'linear',
              x: 0,
              y: 0,
              x2: 0,
              y2: 1,
              colorStops: [
                { offset: 0, color: '#0099FF' },
                { offset: 1, color: '#0066CC' }
              ]
            }
          },
          label: {
            show: true,
            position: 'top',
            formatter: '{c}元/㎡',
            fontSize: 11
          },
          barWidth: '50%'
        }]
      };
    },
    
    // 租金分布饼图（以同和为例）
    rentDistributionOption() {
      const tongheData = rentData.tonghe.rentDistribution;
      
      return {
        tooltip: {
          trigger: 'item',
          formatter: '{b}: {c}套 ({d}%)'
        },
        legend: {
          orient: 'vertical',
          right: '10%',
          top: 'center'
        },
        series: [{
          type: 'pie',
          radius: ['40%', '70%'],
          center: ['40%', '50%'],
          data: tongheData.map(d => ({
            name: d.range + '元',
            value: d.count
          })),
          emphasis: {
            itemStyle: {
              shadowBlur: 10,
              shadowOffsetX: 0,
              shadowColor: 'rgba(0, 0, 0, 0.5)'
            }
          },
          label: {
            formatter: '{b}\n{d}%'
          }
        }]
      };
    },
    
    // 象限图
    quadrantOption() {
      const data = quadrantData.map(d => [d.time, d.rent, d.station]);
      
      return {
        tooltip: {
          trigger: 'item',
          formatter: (params) => {
            return `${params.data[2]}<br/>通勤时间: ${params.data[0]}分钟<br/>租金: ${params.data[1]}元`;
          }
        },
        grid: {
          left: '10%',
          right: '10%',
          bottom: '10%',
          top: '10%',
          containLabel: true
        },
        xAxis: {
          type: 'value',
          name: '通勤时间(分钟)',
          nameLocation: 'middle',
          nameGap: 30,
          splitLine: { show: true }
        },
        yAxis: {
          type: 'value',
          name: '租金(元/月)',
          nameLocation: 'middle',
          nameGap: 50,
          splitLine: { show: true }
        },
        series: [{
          type: 'scatter',
          data: data,
          symbolSize: 20,
          itemStyle: {
            color: (params) => {
              const rent = params.data[1];
              const time = params.data[0];
              if (rent < 2500 && time < 20) return '#67C23A';
              if (rent < 3000) return '#E6A23C';
              return '#F56C6C';
            }
          },
          label: {
            show: true,
            position: 'top',
            formatter: (params) => params.data[2],
            fontSize: 11
          }
        }]
      };
    }
  },
  methods: {
    goNext() {
      this.$parent.nextPage();
    },
    getVariationClass(index) {
      if (index < 16) return 'low';
      if (index < 18) return 'medium';
      return 'high';
    }
  }
}
</script>

